            display: inline-block;
            border: 1px solid #ccc;
            border-radius: 4px;
            box-sizing: border-box;
        }
        input[type="submit"] {
            background-color: #4CAF50;
            color: white;
            cursor: pointer;
        }
        input[type="submit"]:hover {
            background-color: #45a049;
        }
        .captcha-img {
            display: block;
            margin: 10px auto 20px;
            border: 1px solid #ddd;
            border-radius: 4px;
        }
       .info {
            margin-top: 20px;
        }
    </style>
</head>
